import { useState, memo, useEffect } from 'react';
import cls from './Register.module.scss';
import { isMobile } from 'react-device-detect';
import { Button, FieldRow, TaskBoardPanel } from '../../common';
import MessageContainer from '../ProcessesComps/MessageContainer/MessageContainer';
import { createOpenUserInvite } from '../../../services/company.service';
import { take } from 'rxjs';
import { store } from '../../../reduxStore/store';
import { setMessageBar, setShowMenu, setShowSideMenu } from '../../../reduxStore/actions/flowActions';
import { APP_NAME, FLOWHERO } from '../../../shared/utility';
import { useNavigate } from 'react-router-dom';
import MessageBar from '../../TopBar/MessageBar';
import { useSelector } from 'react-redux';
import { checkUserEmail } from '../../../services/user.service';

const RegisterUser = memo(() => {
	const [newUser, setNewUser] = useState({ message: '' });
	const { showMessage, companyData } = useSelector(store => store.flowReducer);
	const { authenticated } = useSelector(store => store.authReducer);

	const [loading, setLoading] = useState(false);
	const [valid, setValid] = useState(false);

	useEffect(() => {
		store.dispatch(setShowSideMenu(false));
		store.dispatch(setShowMenu(false));
	}, []);

	const navigate = useNavigate();
	const createUser = () => {
		if (newUser.email && newUser.firstName && newUser.lastName) {
			setLoading(true);
			createOpenUserInvite({ ...newUser, position_id: companyData?.core_values?.singleUser, company_id: companyData?.id })
				.pipe(take(1))
				.subscribe({
					next: data => {
						setLoading(false);
						store.dispatch(setMessageBar({ noTimeout: true, show: true, message: `We have sent the activation instructions in the email you provided. Close this message and we will forward you to the login page. Thank you `, action: () => navigate('/login') }));
					},
					error: error => {
						setLoading(false);
						store.dispatch(setMessageBar({ noTimeout: true, show: true, message: `Fail! There is something wrong with the details you provided`, color: 'red', action: () => store.dispatch(setMessageBar({ show: false, message: `` })) }));
					},
					complete: () => setLoading(false),
				});
		}
	};

	const checkEmailCompany = () => {
		if (newUser.email) {
			setLoading(true);
			checkUserEmail(newUser)
				.pipe(take(1))
				.subscribe({
					next: data => {
						store.dispatch(setMessageBar({ noTimeout: true, show: true, message: `Email already exists and being used. Please choose another email`, color: 'red', action: () => store.dispatch(setMessageBar({ show: false, message: `` })) }));
						setValid(false);
						setLoading(false);
					},
					error: () => {
						store.dispatch(setMessageBar({ noTimeout: true, show: true, message: `Email ${newUser.email} is available for use.`, action: () => store.dispatch(setMessageBar({ show: false, message: `` })) }));
						setLoading(false);
						setValid(true);
					},
				});
		}
	};
	const renderSuperAdmincreateUser = () => {
		return (
			<div>
				<FieldRow fieldLabel={'Email'} visible={true} style={{ marginTop: '10px' }}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewUser({ ...newUser, email: e.target.value });
							}}
							autoComplete="none"
							value={newUser?.email}
							className={cls.fieldTypeInputU}
							name={'Email'}
						/>
					</div>
				</FieldRow>

				<FieldRow fieldLabel={'First Name'} visible={true} style={{ marginTop: '10px' }}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewUser({ ...newUser, firstName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInputU}
							name={'First Name'}
						/>
					</div>
				</FieldRow>
				<FieldRow fieldLabel={'Last Name'} visible={true} style={{ marginTop: '10px' }}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewUser({ ...newUser, lastName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInputU}
							name={'Last Name'}
						/>
					</div>
				</FieldRow>
			</div>
		);
	};

	return (
		<div className={cls.hostU} style={{ padding: '20px' }}>
			{showMessage?.show && !authenticated ? (
				<MessageBar />
			) : (
				<p
					onClick={() => navigate(`/flowhero/home/${companyData?.slug}`)}
					style={{
						cursor: 'pointer',
						fontFamily: 'var(--app-text-main-font)',
						color: '#4A4A4A',
						textDecoration: 'underline',
						paddingLeft: '10px',
						display: isMobile ? 'none' : '',
					}}
				>
					Home
				</p>
			)}
			<div className={cls.centeredColumn} style={{ border: '1px solid var(--app-color-gray-dark)', margin: 'auto', marginTop: '100px', width: isMobile ? '100%' : '40%', minWidth: isMobile ? '' : '400px' }}>
				{newUser?.message !== '' && <MessageContainer message={newUser?.message} onClick={() => setNewUser({ ...newUser, message: '' })} />}
				<br />
				<FLOWHERO size={'40px'} />
				<div className={cls.headerTopBarContainerU}>{`${companyData?.display_name} SIGNUP`}</div>

				{/* <p className={cls.subheadersU}>{`Sign-up, its quick and easy`}</p> */}
				<br />

				{valid ? (
					renderSuperAdmincreateUser()
				) : (
					<FieldRow fieldLabel={'Email'} visible={true}>
						<div className={cls.fieldRowContainer}>
							<input
								onChange={e => {
									setNewUser({ ...newUser, email: e.target.value });
								}}
								autoComplete="none"
								style={{ border: '2px solid gray' }}
								className={cls.fieldTypeInputU}
								name={'Email'}
							/>
						</div>
					</FieldRow>
				)}
				<div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', margin: '20px' }}>
					{valid ? <Button clicked={createUser} title={'Sign me up'} loading={loading} /> : <Button clicked={checkEmailCompany} title={'Check email address availability'} loading={loading} />}
				</div>
			</div>
		</div>
	);
});

export default RegisterUser;
